/* ── State Global ─────────────────────────────────────────────── */
let db              = [];   // data halaman saat ini saja
let totalRecords    = 0;    // total data di server
let currentUser     = null;
let currentDetailId = null;
let editId          = null;
let PAGE            = 1;
let AI_PAGE         = 1;
const PER_PAGE      = 25;


/* ============================================================
   DATABASE
   ============================================================ */

async function initDB() {
  try {
    const res = await apiFetch('/api/alumni?page=1&per_page=' + PER_PAGE);
    if (res.ok) {
      db = res.data || [];
      totalRecords = res.total || 0;
      console.log('[DB] Supabase OK — total:', totalRecords);
      return;
    }
  } catch (e) {
    console.warn('[DB] Supabase tidak tersedia, pakai data lokal');
  }
  db = ALUMNI_DATA;
  totalRecords = ALUMNI_DATA.length;
}

function saveLocal() {
  try { localStorage.setItem('ts_db_v2', JSON.stringify(db)); } catch (e) {}
}

function syncOne(updated) {
  const i = db.findIndex(a => a.id === updated.id);
  if (i >= 0) db[i] = { ...db[i], ...updated };
}


/* ============================================================
   HTTP HELPER
   ============================================================ */

async function apiFetch(path, opts = {}) {
  const r = await fetch(API_BASE + path, {
    ...opts,
    headers: { 'Content-Type': 'application/json', ...(opts.headers || {}) }
  });
  const d = await r.json().catch(() => ({}));
  if (!r.ok && !d.ok) throw new Error(d.error || 'HTTP ' + r.status);
  return d;
}


/* ============================================================
   AUTENTIKASI
   ============================================================ */

const FALLBACK_USERS = {
  admin:    { pass: 'admin123', role: 'Administrator' },
  operator: { pass: 'op2024',   role: 'Operator' },
  viewer:   { pass: 'view2024', role: 'Viewer' }
};

async function doLogin() {
  const u   = document.getElementById('lUser').value.trim();
  const p   = document.getElementById('lPass').value;
  const err = document.getElementById('lErr');

  let ok = false, role = '';
  try {
    const res = await apiFetch('/api/login', { method: 'POST', body: JSON.stringify({ username: u, password: p }) });
    if (res.ok) { ok = true; role = res.role; }
  } catch (e) {
    if (FALLBACK_USERS[u] && FALLBACK_USERS[u].pass === p) {
      ok = true; role = FALLBACK_USERS[u].role;
    }
  }

  if (ok) {
    currentUser = { username: u, role };
    document.getElementById('loginPage').style.display = 'none';
    document.getElementById('mainApp').classList.remove('hidden');
    document.getElementById('navRole').textContent = role + ': ' + u;
    err.style.display = 'none';
    await initDB();
    populateFilters();
    renderDashboard();
    renderTable();
    renderAIQueue();
  } else {
    err.style.display = 'block';
  }
}

function doLogout() {
  currentUser = null;
  document.getElementById('loginPage').style.display = 'flex';
  document.getElementById('mainApp').classList.add('hidden');
  document.getElementById('lUser').value = '';
  document.getElementById('lPass').value = '';
}

document.addEventListener('DOMContentLoaded', () => {
  document.getElementById('lPass').addEventListener('keydown', e => { if (e.key === 'Enter') doLogin(); });
  document.getElementById('lUser').addEventListener('keydown', e => { if (e.key === 'Enter') document.getElementById('lPass').focus(); });
});


/* ============================================================
   NAVIGASI TAB
   ============================================================ */

function goTab(tab, btn) {
  document.querySelectorAll('.tab').forEach(b => b.classList.remove('on'));
  btn.classList.add('on');
  ['dashboard','data','tambah'].forEach(t =>
    document.getElementById('tab-' + t).classList.toggle('hidden', t !== tab)
  );
  if (tab === 'dashboard') renderDashboard();
  if (tab === 'data')      { populateFilters(); renderTable(); }
}


/* ============================================================
   HELPERS
   ============================================================ */

function completeness(a) {
  let f = 0;
  if (a.email)  f++; if (a.hp)          f++;
  if (a.kerja)  f++; if (a.posisi)       f++;
  if (a.status) f++; if (a.alamat_kerja) f++;
  if (a.linkedin || a.ig || a.fb || a.tiktok) f++;
  if (a.kerja_linkedin || a.kerja_ig || a.kerja_fb || a.kerja_web) f++;
  return Math.round(f / 8 * 100);
}

const FAK_SHORT = {
  'Keguruan dan Ilmu Pendidikan':'FKIP','Teknik':'FT',
  'Ilmu Sosial dan Ilmu Politik':'FISIP','Ekonomi dan Bisnis':'FEB',
  'Ekonomi':'FE','Ilmu Kesehatan':'FIK','Psikologi':'FPsi',
  'Pertanian dan Peternakan':'FPP','Pascasarjana':'PPs',
  'Hukum':'FH','Kedokteran':'FK','Agama Islam':'FAI'
};
function fakShort(f) { return FAK_SHORT[f] || f.substring(0,6); }

function statusBadge(s) {
  if (!s) return '<span class="badge badge-belum">—</span>';
  const c = s==='PNS'?'badge-pns':s==='Swasta'?'badge-swasta':'badge-wirausaha';
  return `<span class="badge ${c}">${s}</span>`;
}

function dataBadge(a) {
  const c = completeness(a);
  if (c>=75) return '<span class="badge badge-lengkap">Lengkap</span>';
  if (c>0)   return `<span class="badge badge-partial">${c}%</span>`;
  return '<span class="badge badge-belum">Kosong</span>';
}

async function populateFilters() {
  const sel = document.getElementById('filterFak');
  try {
    const res = await apiFetch('/api/alumni/facets');
    if (res.ok && res.fakultas) {
      sel.innerHTML = '<option value="">Semua Fakultas</option>' +
        res.fakultas.map(f => `<option value="${f}">${f}</option>`).join('');
      return;
    }
  } catch (e) {}
  const faks = [...new Set(db.map(a => a.fakultas))].filter(Boolean).sort();
  sel.innerHTML = '<option value="">Semua Fakultas</option>' +
    faks.map(f => `<option value="${f}">${f}</option>`).join('');
}


/* ============================================================
   DASHBOARD
   ============================================================ */

async function renderDashboard() {
  let total = totalRecords, pns = 0, swasta = 0, wu = 0;
  let filled = 0, done = 0;
  let items = [['Email',0],['HP/WA',0],['Kerja',0],['LinkedIn',0],['Instagram',0],['TikTok',0]];

  try {
    const res = await apiFetch('/api/stats');
    if (res.ok && res.data) {
      const s = res.data;
      total  = parseInt(s.total)       || 0;
      pns    = parseInt(s.pns)         || 0;
      swasta = parseInt(s.swasta)      || 0;
      wu     = parseInt(s.wirausaha)   || 0;
      filled = parseInt(s.punya_kerja) || 0;
      done   = parseInt(s.sudah_dicari)|| 0;
      items  = [
        ['Email',    parseInt(s.punya_email)   || 0],
        ['HP/WA',    parseInt(s.punya_hp)      || 0],
        ['Kerja',    parseInt(s.punya_kerja)   || 0],
        ['LinkedIn', parseInt(s.punya_linkedin)|| 0],
        ['Instagram',parseInt(s.punya_ig)      || 0],
        ['TikTok',   parseInt(s.punya_tiktok)  || 0],
      ];
      totalRecords = total;
    }
  } catch (e) {
    // fallback: hitung dari halaman saat ini
    total  = db.length; pns = db.filter(a=>a.status==='PNS').length;
    swasta = db.filter(a=>a.status==='Swasta').length; wu = db.filter(a=>a.status==='Wirausaha').length;
    filled = db.filter(a=>a.kerja).length; done = db.filter(a=>a.ai_searched).length;
  }

  if (total === 0) total = 1; // hindari divisi 0
  document.getElementById('dashStats').innerHTML = `
    <div class="stat"><div class="stat-num">${totalRecords.toLocaleString('id')}</div><div class="stat-lbl">Total Alumni</div>
      <div class="stat-bar" style="background:var(--blue);width:100%"></div></div>
    <div class="stat"><div class="stat-num">${pns.toLocaleString('id')}</div><div class="stat-lbl">PNS / ASN</div>
      <div class="stat-bar" style="background:var(--green);width:${pns/total*100}%"></div></div>
    <div class="stat"><div class="stat-num">${swasta.toLocaleString('id')}</div><div class="stat-lbl">Swasta</div>
      <div class="stat-bar" style="background:var(--blue);width:${swasta/total*100}%"></div></div>
    <div class="stat"><div class="stat-num">${wu.toLocaleString('id')}</div><div class="stat-lbl">Wirausaha</div>
      <div class="stat-bar" style="background:var(--amber);width:${wu/total*100}%"></div></div>`;

  // Recent alumni: ambil dari server
  let recent = [];
  try {
    const r = await apiFetch('/api/alumni?per_page=8&order_by=updated_at&order_dir=desc');
    if (r.ok) recent = r.data.filter(a => a.updated_at);
  } catch (e) {
    recent = db.filter(a=>a.updated_at).sort((a,b)=>b.updated_at.localeCompare(a.updated_at)).slice(0,8);
  }

  document.getElementById('dashRecent').innerHTML = recent.length
    ? recent.map(a => `
        <div class="dash-row">
          <div><div class="dash-rname">${a.nama}</div>
               <div class="dash-rsub">${a.posisi||'—'} · ${a.kerja||'—'}</div></div>
          ${statusBadge(a.status)}
        </div>`).join('')
    : '<div class="empty">Belum ada data</div>';

  const pct = Math.round(filled/total*100);
  const r = 18, circ = 2*Math.PI*r, off = circ-(pct/100)*circ;
  document.getElementById('dashComplete').innerHTML = `
    <div style="text-align:center;padding:1rem">
      <svg class="progress-ring" viewBox="0 0 48 48">
        <circle class="ring-bg" cx="24" cy="24" r="${r}"/>
        <circle class="ring-fg" cx="24" cy="24" r="${r}" stroke="var(--blue)"
          stroke-dasharray="${circ}" stroke-dashoffset="${off}"/>
        <text x="24" y="28" text-anchor="middle" fill="var(--text)" font-size="9" font-weight="700">${pct}%</text>
      </svg>
      <div style="font-size:13px;color:var(--text2);margin-top:4px">${filled.toLocaleString('id')} / ${total.toLocaleString('id')} terisi</div>
      <div style="font-size:11px;color:var(--text3)">${done.toLocaleString('id')} data lengkap</div>
    </div>
    <div style="padding:0 .5rem">
      ${items.map(([l,v]) => `
        <div style="margin-bottom:8px">
          <div style="display:flex;justify-content:space-between;font-size:11px;color:var(--text3);margin-bottom:3px">
            <span>${l}</span><span>${v.toLocaleString('id')}</span></div>
          <div style="height:3px;background:var(--bg4);border-radius:2px">
            <div style="height:3px;background:var(--blue);border-radius:2px;width:${v/total*100}%"></div>
          </div>
        </div>`).join('')}
    </div>`;
}


/* ============================================================
   TABEL DATA ALUMNI
   ============================================================ */

function filterData() {
  const q  = (document.getElementById('searchQ')?.value      || '').toLowerCase();
  const fk = (document.getElementById('filterFak')?.value    || '');
  const st = (document.getElementById('filterStatus')?.value || '');
  const dt = (document.getElementById('filterData')?.value   || '');
  return db.filter(a => {
    if (q  && ![a.nama,a.nim+'',a.kerja,a.posisi,a.prodi].some(v=>v&&v.toLowerCase().includes(q))) return false;
    if (fk && a.fakultas !== fk) return false;
    if (st && a.status   !== st) return false;
    if (dt === 'lengkap' && completeness(a) < 75)  return false;
    if (dt === 'belum'   && completeness(a) >= 75) return false;
    return true;
  });
}

async function renderTable() {
  const q  = (document.getElementById('searchQ')?.value      || '');
  const fk = (document.getElementById('filterFak')?.value    || '');
  const st = (document.getElementById('filterStatus')?.value || '');
  const dt = (document.getElementById('filterData')?.value   || '');

  const params = new URLSearchParams({ page: PAGE, per_page: PER_PAGE });
  if (q)  params.set('search', q);
  if (fk) params.set('fakultas', fk);
  if (st) params.set('status', st);
  if (dt === 'lengkap') params.set('ai_searched', 'true');
  if (dt === 'belum')   params.set('ai_searched', 'false');

  try {
    const res = await apiFetch('/api/alumni?' + params.toString());
    if (res.ok) {
      db = res.data || [];
      totalRecords = res.total || 0;
    }
  } catch (e) {
    // fallback: filter lokal
    const filtered = filterData();
    const pages = Math.ceil(filtered.length / PER_PAGE);
    if (PAGE > pages) PAGE = Math.max(1, pages);
    db = filtered.slice((PAGE-1)*PER_PAGE, PAGE*PER_PAGE);
    totalRecords = filtered.length;
  }

  const pages = Math.ceil(totalRecords / PER_PAGE);
  if (PAGE > pages) PAGE = Math.max(1, pages);
  const isViewer = currentUser?.role === 'Viewer';

  document.getElementById('rowCount').textContent = `(${totalRecords.toLocaleString('id')} alumni)`;
  document.getElementById('tblBody').innerHTML = db.length
    ? db.map(a => `
        <tr>
          <td class="td-name">${a.nama}</td>
          <td><span style="font-size:11px;color:var(--text3)">${fakShort(a.fakultas)}</span></td>
          <td style="font-size:11px">${a.prodi.substring(0,22)}${a.prodi.length>22?'…':''}</td>
          <td style="font-size:11px">${a.tanggal_lulus}</td>
          <td>${a.kerja?`<span style="font-size:12px">${a.kerja.substring(0,24)}</span>`:'<span style="color:var(--text3);font-size:11px">—</span>'}</td>
          <td>${statusBadge(a.status)}</td>
          <td>${dataBadge(a)}</td>
          <td>
            <button class="btn-sm" onclick="viewDetail(${a.id})">Detail</button>
            ${!isViewer?`<button class="btn-sm btn-ai" onclick="startEdit(${a.id})">Edit</button>`:''}
          </td>
        </tr>`).join('')
    : '<tr><td colspan="8" class="empty">Tidak ada data ditemukan</td></tr>';

  renderPagination(pages, 'pagination', p => { PAGE = p; renderTable(); });
}

function renderPagination(pages, id, cb) {
  const el = document.getElementById(id);
  if (pages<=1) { el.innerHTML=''; return; }
  const cur = id==='pagination'?PAGE:AI_PAGE;
  const btn = p => p===cur
    ? `<button class="pg-btn on">${p}</button>`
    : `<button class="pg-btn" onclick="(${cb.toString()})(${p})">${p}</button>`;
  let h = '';
  if (cur>1)     h += `<button class="pg-btn" onclick="(${cb.toString()})(${cur-1})">←</button>`;
  for (let p=Math.max(1,cur-2); p<=Math.min(pages,cur+2); p++) h += btn(p);
  if (cur<pages) h += `<button class="pg-btn" onclick="(${cb.toString()})(${cur+1})">→</button>`;
  h += `<span class="pg-info">Hal ${cur} / ${pages}</span>`;
  el.innerHTML = h;
}


/* ============================================================
   ANTRIAN — tab yang menampilkan semua alumni untuk dikelola
   ============================================================ */

function renderAIQueue() {
  const q     = (document.getElementById('aiSearchQ')?.value || '').toLowerCase();
  const data  = db.filter(a => !q || a.nama.toLowerCase().includes(q));
  const pages = Math.ceil(data.length/PER_PAGE);
  if (AI_PAGE>pages) AI_PAGE = Math.max(1,pages);
  const slice = data.slice((AI_PAGE-1)*PER_PAGE, AI_PAGE*PER_PAGE);

  document.getElementById('aiQueueBody').innerHTML = slice.map(a => `
    <tr>
      <td><input type="checkbox" class="ai-check" value="${a.id}"></td>
      <td class="td-name">${a.nama}</td>
      <td style="font-size:11px">${a.prodi.substring(0,20)}…</td>
      <td style="font-size:11px">${a.tanggal_lulus}</td>
      <td>${statusBadge(a.status)}</td>
      <td style="font-size:11px;color:var(--text3)">${a.kerja||'—'}</td>
      <td>
        <button class="btn-sm" onclick="viewDetail(${a.id})">Detail</button>
        <button class="btn-sm btn-ai" onclick="startEdit(${a.id})">Edit</button>
      </td>
    </tr>`).join('') || '<tr><td colspan="7" class="empty">Tidak ada data</td></tr>';

  renderPagination(pages, 'aiPagination', p => { AI_PAGE = p; renderAIQueue(); });
}

function toggleAll(cb) {
  document.querySelectorAll('.ai-check').forEach(c => c.checked = cb.checked);
}


/* ============================================================
   MODAL DETAIL
   ============================================================ */

function viewDetail(id) {
  currentDetailId = id;
  const a = db.find(x => x.id===id);
  document.getElementById('modalName').textContent = a.nama;

  const row = (lbl, val, link=false) =>
    `<div class="ditem"><label>${lbl}</label>${
      link && val
        ? `<a href="${val.startsWith('http')?val:'https://'+val}" target="_blank">${val}</a>`
        : `<span>${val||'—'}</span>`
    }</div>`;

  document.getElementById('modalContent').innerHTML = `
    <div class="detail-grid">
      ${row('NIM', a.nim)}              ${row('Angkatan', a.tahun_masuk)}
      ${row('Fakultas', a.fakultas)}    ${row('Program Studi', a.prodi)}
      ${row('Tanggal Lulus', a.tanggal_lulus)} <div></div>
      <div class="dsec">Kontak Personal</div>
      ${row('Email', a.email, true)}    ${row('No. HP / WA', a.hp)}
      <div class="dsec">Sosial Media Pribadi</div>
      ${row('LinkedIn', a.linkedin, true)} ${row('Instagram', a.ig)}
      ${row('Facebook', a.fb, true)}       ${row('TikTok',    a.tiktok)}
      <div class="dsec">Informasi Pekerjaan</div>
      ${row('Tempat Bekerja', a.kerja)}    ${row('Posisi / Jabatan', a.posisi)}
      ${row('Status', a.status)}           ${row('Alamat Kerja', a.alamat_kerja)}
      <div class="dsec">Sosial Media Tempat Kerja</div>
      ${row('LinkedIn', a.kerja_linkedin, true)} ${row('Instagram', a.kerja_ig)}
      ${row('Facebook', a.kerja_fb, true)}        ${row('Website',   a.kerja_web, true)}
    </div>`;

  document.getElementById('detailModal').classList.add('open');
}

function closeModal() { document.getElementById('detailModal').classList.remove('open'); }

function editFromDetail() {
  closeModal();
  startEdit(currentDetailId);
  goTab('tambah', document.querySelectorAll('.tab')[2]);
}

document.getElementById('detailModal').addEventListener('click', e => {
  if (e.target === document.getElementById('detailModal')) closeModal();
});


