function startEdit(id) {
  editId = id;
  const a = db.find(x => x.id===id);
  document.getElementById('formTitle').textContent = 'Edit Data: ' + a.nama;
  document.getElementById('f_nama').value = a.nama;
  document.getElementById('f_nim').value  = a.nim;
  ['linkedin','ig','fb','tiktok','email','hp',
   'kerja','posisi','status','alamat_kerja',
   'kerja_linkedin','kerja_ig','kerja_fb','kerja_web'
  ].forEach(k => { const el = document.getElementById('f_'+k); if(el) el.value = a[k]||''; });
  goTab('tambah', document.querySelectorAll('.tab')[2]);
}

async function saveAlumni() {
  if (!editId) { showFormMsg('Pilih alumni dari tabel untuk diedit.','err'); return; }
  const g = k => document.getElementById('f_'+k).value.trim();
  const patch = {
    nama:g('nama'), email:g('email'), hp:g('hp'),
    linkedin:g('linkedin'), ig:g('ig'), fb:g('fb'), tiktok:g('tiktok'),
    kerja:g('kerja'), posisi:g('posisi'), status:g('status'), alamat_kerja:g('alamat_kerja'),
    kerja_linkedin:g('kerja_linkedin'), kerja_ig:g('kerja_ig'),
    kerja_fb:g('kerja_fb'), kerja_web:g('kerja_web'),
    updated_at: new Date().toISOString()
  };
  try {
    await apiFetch(`/api/alumni/${editId}`, { method:'PATCH', body:JSON.stringify(patch) });
  } catch (e) { console.warn('Server tidak tersedia, simpan lokal'); }
  syncOne({ id: editId, ...patch });
  editId = null;
  showFormMsg('Data berhasil disimpan!','ok');
  await renderTable(); renderDashboard();
  setTimeout(() => {
    document.getElementById('formMsg').textContent = '';
    document.getElementById('formTitle').textContent = 'Edit Data Alumni';
  }, 2500);
}

function resetForm() {
  editId = null;
  document.getElementById('formTitle').textContent = 'Edit Data Alumni';
  ['nama','linkedin','ig','fb','tiktok','email','hp',
   'kerja','posisi','status','alamat_kerja',
   'kerja_linkedin','kerja_ig','kerja_fb','kerja_web'
  ].forEach(k => { const el = document.getElementById('f_'+k); if(el) el.value=''; });
  document.getElementById('formMsg').textContent = '';
}

function showFormMsg(msg, type) {
  const el = document.getElementById('formMsg');
  el.textContent = msg;
  el.className   = 'form-msg ' + type;
}

